42	pub(crate) fn parse_bootstrap_host_from_url(url: &str) -> String {
43	    let metadata_url = match url.rsplit_once('@') {
44	        Some((base_url, rank)) if rank.parse::<usize>().is_ok() => base_url,
45	        _ => url,
46	    };
47	
48	    match url::Url::parse(metadata_url) {
49	        Ok(parsed) => parsed.host_str().unwrap_or("localhost").to_string(),
50	        Err(_) if !metadata_url.contains("://") => {
51	            match url::Url::parse(&format!("http://{}", metadata_url)) {
52	                Ok(parsed) => parsed.host_str().unwrap_or("localhost").to_string(),
53	                Err(_) => {
54	                    tracing::warn!(
55	                        "Failed to parse URL '{}', defaulting to localhost",
56	                        metadata_url
57	                    );
58	                    "localhost".to_string()
59	                }
60	            }
61	        }
62	        Err(_) => {
63	            tracing::warn!(
64	                "Failed to parse URL '{}', defaulting to localhost",
65	                metadata_url
66	            );
67	            "localhost".to_string()
68	        }
