77	impl WorkerRoutingKeyLoad {
78	    pub fn new(url: impl Into<String>) -> Self {
79	        Self {
80	            url: url.into(),
81	            active_routing_keys: dashmap::DashMap::new(),
82	        }
83	    }
84	
85	    pub fn value(&self) -> usize {
86	        self.active_routing_keys.len()
87	    }
88	
89	    pub fn increment(&self, routing_key: &str) {
90	        *self
91	            .active_routing_keys
92	            .entry(routing_key.to_string())
93	            .or_insert(0) += 1;
94	        self.update_metrics();
95	    }
96	
97	    pub fn decrement(&self, routing_key: &str) {
98	        use dashmap::mapref::entry::Entry;
99	
100	        match self.active_routing_keys.entry(routing_key.to_string()) {
101	            Entry::Occupied(mut entry) => {
102	                let counter = entry.get_mut();
103	                if *counter > 0 {
104	                    *counter -= 1;
105	                    if *counter == 0 {
106	                        entry.remove();
107	                    }
108	                } else {
109	                    tracing::warn!(
110	                        worker_url = %self.url,
111	                        routing_key = %routing_key,
112	                        "Attempted to decrement routing key counter that is already at 0"
113	                    );
114	                }
115	            }
116	            Entry::Vacant(_) => {
117	                tracing::warn!(
118	                    worker_url = %self.url,
119	                    routing_key = %routing_key,
120	                    "Attempted to decrement non-existent routing key"
121	                );
122	            }
123	        }
124	        self.update_metrics();
125	    }
126	
127	    fn update_metrics(&self) {
128	        Metrics::set_worker_routing_keys_active(&self.url, self.value());
129	    }
130	}
